using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = "";

    [LoadColumn(1)]
    public string Description { get; set; } = "";

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = "";
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = "";

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = "";
    public Dictionary<string, float> Confidence { get; set; } = new();
}

namespace TicketClassifier.Services;

/// <summary>
/// Stores label-to-score-index mapping discovered during training.
/// Registered as a singleton and populated by ModelTrainerService at startup.
/// </summary>
public class ModelMetadata
{
    public string[] Labels { get; set; } = [];
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains the multiclass classification model at startup, logs cross-validation
/// metrics, and saves the final model to disk for PredictionEnginePool.
/// </summary>
public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly ModelMetadata _metadata;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainerService(
        ILogger<ModelTrainerService> logger,
        ModelMetadata metadata,
        IWebHostEnvironment env)
    {
        _logger = logger;
        _metadata = metadata;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                "Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate to estimate performance on this small dataset
        var cvResults = mlContext.MulticlassClassification.CrossValidate(
            data, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        foreach (var (result, i) in cvResults.Select((r, i) => (r, i)))
        {
            _logger.LogInformation(
                "Fold {Fold}: MacroAccuracy={MacroAccuracy:F4}, LogLoss={LogLoss:F4}",
                i + 1, result.Metrics.MacroAccuracy, result.Metrics.LogLoss);

            foreach (var row in result.Metrics.PerClassLogLoss.Select((v, j) => (v, j)))
            {
                _logger.LogInformation("  Class {Class} LogLoss={LogLoss:F4}", row.j, row.v);
            }
        }

        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);

        _logger.LogInformation(
            "Cross-Validation Average: MacroAccuracy={MacroAccuracy:F4}, " +
            "MicroAccuracy={MicroAccuracy:F4}, LogLoss={LogLoss:F4}",
            avgMacro, avgMicro, avgLogLoss);

        // Train final model on all data
        var model = pipeline.Fit(data);

        // Extract label names from the Score column slot metadata
        var transformedData = model.Transform(data);
        VBuffer<ReadOnlyMemory<char>> slotNames = default;
        transformedData.Schema["Score"].GetSlotNames(ref slotNames);
        _metadata.Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        _logger.LogInformation("Labels discovered: {Labels}", string.Join(", ", _metadata.Labels));

        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class PredictionController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _pool;
    private readonly ModelMetadata _metadata;

    public PredictionController(
        PredictionEnginePool<TicketInput, TicketPrediction> pool,
        ModelMetadata metadata)
    {
        _pool = pool;
        _metadata = metadata;
    }

    [HttpPost]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _metadata.Labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_metadata.Labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

